extract_s123:
```lean
theorem main_returns_value_within_bounds :
    let array : Array UInt8 := (Array.mkArray (1024 * 1024) 1)
    let n := 1024 * 1024
    let res := (List.range n).foldl (fun acc i =>
      (List.range n).foldl (fun acc' j =>
        (List.range n).foldl (fun acc'' k =>
          acc''.set! i (acc''.get! j + acc''.get! k)
        ) acc'
      ) acc
    ) array
    res.get! 100 = 2 := by
  native_decide

theorem array_accesses_are_valid :
    let array : Array UInt8 := (Array.mkArray (1024 * 1024) 1)
    let n := 1024 * 1024
    let res := (List.range n).foldl (fun acc i =>
      (List.range n).foldl (fun acc' j =>
        (List.range n).foldl (fun acc'' k =>
          acc''.set! i (acc''.get! j + acc''.get! k)
        ) acc'
      ) acc
    ) array
    100 < res.size := by
  native_decide

theorem check_properties :
    (init(main()) = 2) Ōł¦ (100 < (init(main())).size) := by
  native_decide

theorem main_property :
    let array : Array UInt8 := (Array.mkArray (1024 * 1024) 1)
    let n := 1024 * 1024
    let res := (List.range n).foldl (fun acc i =>
      (List.range n).foldl (fun acc' j =>
        (List.range n).foldl (fun acc'' k =>
          acc''.set! i (acc''.get! j + acc''.get! k)
        ) acc'
      ) acc
    ) array
    res.get! 100 = 2 Ōł¦ 100 < res.size := by
  native_decide

theorem main_satisfies_checks :
    let array : Array UInt8 := (Array.mkArray (1024 * 1024) 1)
    let n := 1024 * 1024
    let res := (List.range n).foldl (fun acc i =>
      (List.range n).foldl (fun acc' j =>
        (List.range n).foldl (fun acc'' k =>
          acc''.set! i (acc''.get! j + acc''.get! k)
        ) acc'
      ) acc
    ) array
    res.get! 100 = 2 Ōł¦ 100 < res.size := by
  native_decide
```

